import{_ as e,o as r,c as o,a2 as a}from"./chunks/framework.ZhLefgN8.js";const u=JSON.parse('{"title":"登录注册","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"getting-started/login-and-register.md","filePath":"zh-CN/getting-started/login-and-register.md"}'),l={name:"getting-started/login-and-register.md"};function i(d,t,n,s,h,c){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="登录注册" tabindex="-1">登录注册 <a class="header-anchor" href="#登录注册" aria-label="Permalink to &quot;登录注册&quot;">​</a></h1><p>长桥 App 采用手机号一体化设计：<strong>首次登录即自动完成注册</strong>，无需单独注册流程。</p><h2 id="登录方式总览" tabindex="-1">登录方式总览 <a class="header-anchor" href="#登录方式总览" aria-label="Permalink to &quot;登录方式总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>登录方式</th><th>入口</th><th>说明</th></tr></thead><tbody><tr><td>手机号 + OTP 验证码</td><td>默认页面</td><td>输入手机号发送验证码，首次使用自动注册</td></tr><tr><td>手机号 + 密码</td><td>Select another method</td><td>需提前设置密码</td></tr><tr><td>Login ID</td><td>Select another method</td><td>使用平台分配的登录 ID + 密码</td></tr><tr><td>邮箱</td><td>Select another method</td><td>使用绑定邮箱 + 密码登录</td></tr><tr><td>支付宝</td><td>页面底部图标</td><td>一键授权登录（适用于已绑定的账户）</td></tr><tr><td>Google</td><td>底部 <code>···</code> → 更多</td><td>使用 Google 账号授权登录</td></tr><tr><td>Facebook</td><td>底部 <code>···</code> → 更多</td><td>使用 Facebook 账号授权登录</td></tr></tbody></table><hr><h2 id="手机号-otp-验证码-默认方式" tabindex="-1">手机号 + OTP 验证码（默认方式） <a class="header-anchor" href="#手机号-otp-验证码-默认方式" aria-label="Permalink to &quot;手机号 + OTP 验证码（默认方式）&quot;">​</a></h2><ol><li>打开长桥 App，进入登录页面</li><li>点击左侧区号（默认 <code>+86</code>）选择手机号归属地区</li><li>输入手机号码</li><li>勾选下方用户协议复选框</li><li>点击「Send OTP」，系统向手机发送一次性验证码</li><li>在验证码输入页输入收到的验证码，完成登录。验证码自发送后 5 分钟内有效，过期需重新发送</li></ol><blockquote><p><strong>首次登录即自动注册</strong>：若该手机号尚未注册账户，验证码验证通过后系统自动创建账户，无需填写额外信息。</p></blockquote><hr><h2 id="其他登录方式" tabindex="-1">其他登录方式 <a class="header-anchor" href="#其他登录方式" aria-label="Permalink to &quot;其他登录方式&quot;">​</a></h2><p>点击「Select another method」弹出选择菜单：</p><ul><li><strong>Phone Number and Password</strong>：使用手机号 + 账户密码登录，需提前在 App 内设置密码</li><li><strong>Login ID</strong>：使用平台分配的专属登录 ID + 密码。登录后可在「我的 → 账户安全」查看当前账户的 Login ID</li><li><strong>Email</strong>：使用绑定邮箱 + 密码登录</li></ul><hr><h2 id="第三方快捷登录" tabindex="-1">第三方快捷登录 <a class="header-anchor" href="#第三方快捷登录" aria-label="Permalink to &quot;第三方快捷登录&quot;">​</a></h2><p>登录页底部有两个快捷入口：</p><ul><li><strong>支付宝图标</strong>：直接点击，通过支付宝授权一键登录</li><li><strong><code>···</code> 图标</strong>：点击展开更多第三方登录方式，目前支持 <strong>Google</strong> 和 <strong>Facebook</strong></li></ul><p>第三方登录时，系统以授权账号关联的手机号或邮箱匹配已有账户。若有匹配账户则直接登录；若无匹配账户则创建新账号。建议首次使用前确认关联信息，避免产生重复账号。</p><hr><h2 id="选择手机号归属地区" tabindex="-1">选择手机号归属地区 <a class="header-anchor" href="#选择手机号归属地区" aria-label="Permalink to &quot;选择手机号归属地区&quot;">​</a></h2><p>点击输入框左侧区号（如 <code>+86</code>）进入国家/地区选择页：</p><ul><li><strong>搜索</strong>：在顶部搜索框输入国家或地区名称快速定位</li><li><strong>常用地区</strong>（快速选择）： <ul><li>中国大陆 +86</li><li>澳门 +853</li><li>香港 +852</li><li>台湾 +886</li><li>新加坡 +65</li></ul></li><li>完整列表按字母顺序排列，右侧有字母索引可快速跳转</li></ul><hr><h2 id="邀请码" tabindex="-1">邀请码 <a class="header-anchor" href="#邀请码" aria-label="Permalink to &quot;邀请码&quot;">​</a></h2><p>登录页右上角「Invitation Code」为可展开输入框，展开后在手机号输入框下方出现邀请码输入栏。</p><ul><li>若通过好友邀请注册，请在注册前填入邀请码，确保邀请关系正确绑定</li><li>邀请码须在<strong>首次注册完成前</strong>填写，注册后无法补填</li></ul><hr><h2 id="用户协议" tabindex="-1">用户协议 <a class="header-anchor" href="#用户协议" aria-label="Permalink to &quot;用户协议&quot;">​</a></h2><p>点击「Send OTP」前需勾选协议，包含：</p><ul><li><strong>Service Agreement</strong>（服务协议）</li><li><strong>Privacy Policy</strong>（隐私政策）</li><li><strong>Third-Party Personal Information Sharing Inventory</strong>（第三方个人信息共享清单）</li></ul><p>点击对应文字链接可查看完整协议内容。未勾选协议时，「Send OTP」按钮为置灰不可点击状态。</p><hr><h2 id="账号唯一性、安全规则与手机号变更" tabindex="-1">账号唯一性、安全规则与手机号变更 <a class="header-anchor" href="#账号唯一性、安全规则与手机号变更" aria-label="Permalink to &quot;账号唯一性、安全规则与手机号变更&quot;">​</a></h2><ul><li>同一手机号在同一持牌实体下只能对应一个账户；账号以手机号为主要标识，遗失密码可直接用手机号 + OTP 重新登录</li><li>更换手机号时，在旧号码仍可接收短信期间，进入「我的 → 账户安全 → 手机号管理」操作；若旧号码已无法使用，需联系客服提供身份证明进行人工处理</li><li>账户处于冻结状态时，登录后会提示账户异常，需联系客服处理</li><li>长桥不会主动要求您将验证码提供给他人，请勿泄露验证码</li><li>收不到验证码时，请参阅 <a href="./../troubleshooting/收不到短信验证码">收不到短信验证码</a> 排查</li><li>登录遇到问题，可点击页面右上角「Get Help」直接联系客服</li></ul>',33)])])}const p=e(l,[["render",i]]);export{u as __pageData,p as default};
